// Sistema de paginação simples e direto
document.addEventListener('DOMContentLoaded', function() {
    // Sistema principal - cria footers múltiplos com números incrementais
    function createMultiPageSystem() {
        // Remove o footer original do DOM inicial
        const originalFooter = document.querySelector('.footer');
        if (originalFooter) {
            originalFooter.style.display = 'none'; // Esconde mas mantém no DOM
        }

        // Cria footers numerados para impressão
        createNumberedFooters();

        // Event listeners para recriação
        window.addEventListener('beforeprint', createNumberedFooters);
        window.addEventListener('resize', function() {
            setTimeout(createNumberedFooters, 100);
        });
    }

    function createNumberedFooters() {
        // Remove footers anteriores
        const oldFooters = document.querySelectorAll('.footer-numbered');
        oldFooters.forEach(f => f.remove());

        // Calcula número de páginas baseado no conteúdo
        const totalHeight = document.documentElement.scrollHeight;
        const pageHeight = 1123; // ~297mm em pixels (A4)
        const pageCount = Math.max(Math.ceil(totalHeight / pageHeight), 2);

        // Cria um footer numerado para cada página
        for (let i = 1; i <= pageCount; i++) {
            createFooterForPage(i, pageHeight);
        }
    }

    function createFooterForPage(pageNumber, pageHeight) {
        const footer = document.createElement('div');
        footer.className = 'footer footer-numbered';
        footer.style.cssText = `
            position: fixed;
            bottom: 0;
            left: 0;
            right: 0;
            padding: 24px 0 0;
            z-index: 10;
            background: rgba(252, 252, 252, 0.95);
            backdrop-filter: blur(2px);
            page: page-${pageNumber};
            print-color-adjust: exact;
            -webkit-print-color-adjust: exact;
        `;

        footer.innerHTML = `
            <div style="height: 2px; background: #e5e7eb80; margin-bottom: 24px;"></div>
            <div style="display: flex; justify-content: space-between; align-items: center; padding: 0 56px;">
                <div style="display: inline-block;">
                    <img src="Logo completa.png" alt="Wa Project" style="width: 74px; height: 27px; display: block;">
                </div>
                <span style="font-size: 12.5px; color: var(--blue); font-weight: 700;">${pageNumber}</span>
            </div>
        `;

        document.body.appendChild(footer);
    }

    // Inicialização
    createMultiPageSystem();

    // Função para otimizar quebras de página (simplificada)
    function optimizePageBreaks() {
        const sections = document.querySelectorAll('.content-section');
        const pageHeight = window.innerHeight || 800;
        let currentPageHeight = 0;

        sections.forEach(function(section) {
            const sectionHeight = section.offsetHeight;

            if (currentPageHeight + sectionHeight > pageHeight * 0.8) {
                section.style.pageBreakBefore = 'always';
                currentPageHeight = sectionHeight;
            } else {
                currentPageHeight += sectionHeight;
            }
        });
    }

    // Executa otimização se solicitado
    if (window.location.search.includes('optimize=true')) {
        setTimeout(optimizePageBreaks, 200);
    }
});

