// Sistema de paginação JavaScript - substitui contadores CSS que não funcionam no preview
document.addEventListener('DOMContentLoaded', function() {
    // Função principal para numerar páginas
    function setupPageNumbers() {
        // Aguarda fontes e imagens carregarem
        setTimeout(function() {
            calculateAndSetPageNumbers();
        }, 200);

        // Recalcula na mudança de tamanho
        window.addEventListener('resize', function() {
            setTimeout(calculateAndSetPageNumbers, 100);
        });
    }

    function calculateAndSetPageNumbers() {
        const pageHeight = window.innerHeight; // Altura da janela/página
        const footerHeight = 120; // Altura estimada do footer
        const availableHeight = pageHeight - footerHeight;

        // Encontra todas as seções de conteúdo
        const sections = document.querySelectorAll('.content-section');
        const pageBreaks = document.querySelectorAll('.cover-page, .flow-page');

        let pageCount = 1;
        let currentHeight = 0;

        // Método 1: Conta com base nas quebras de página existentes
        if (pageBreaks.length > 0) {
            pageCount = pageBreaks.length;
        } else {
            // Método 2: Calcula com base na altura do conteúdo
            const totalContent = document.querySelector('.content-flow');
            if (totalContent) {
                const totalHeight = totalContent.offsetHeight;
                pageCount = Math.ceil(totalHeight / availableHeight) || 1;
            }
        }

        // Método 3: Detecção mais precisa usando elementos page-break
        const pageBreakElements = document.querySelectorAll('[style*="page-break"], .js-page-break, .cover-page, .flow-page');
        if (pageBreakElements.length > pageCount) {
            pageCount = pageBreakElements.length;
        }

        // Aplica numeração em todos os elementos .pg-num
        applyPageNumbering(pageCount);
    }

    function applyPageNumbering(totalPages) {
        // Força atualização imediata do elemento .pg-num
        const pageNumElements = document.querySelectorAll('.pg-num');

        pageNumElements.forEach(function(element) {
            // Remove o ::after do CSS e substitui por conteúdo JavaScript
            element.innerHTML = '1'; // Sempre começa com página 1
            element.style.fontSize = '12.5px';
            element.style.color = 'var(--blue)';
            element.style.fontWeight = '700';
        });

        // Sistema de incremento para múltiplas páginas
        setTimeout(function() {
            attemptMultiPageNumbering(totalPages);
        }, 100);
    }

    function attemptMultiPageNumbering(totalPages) {
        // Cria um sistema de contadores manuais
        let currentPageNumber = 1;

        // Intercepta eventos de quebra de página
        const observer = new MutationObserver(function(mutations) {
            mutations.forEach(function(mutation) {
                if (mutation.type === 'childList') {
                    updatePageNumbers();
                }
            });
        });

        // Observa mudanças no DOM
        observer.observe(document.body, {
            childList: true,
            subtree: true
        });

        // Força atualização inicial
        updatePageNumbers();
    }

    function updatePageNumbers() {
        // Estratégia simples: conta elementos com quebra de página
        const pageBreakElements = document.querySelectorAll('.cover-page, .flow-page, .js-page-break');
        const pageCount = Math.max(pageBreakElements.length, 2);

        // Atualiza todos os .pg-num encontrados
        const pageNumElements = document.querySelectorAll('.pg-num');
        pageNumElements.forEach(function(element, index) {
            // Para o primeiro elemento, mantém "1"
            // Para elementos subsequentes (se houver), incrementa
            const pageNum = index + 1;
            element.textContent = Math.min(pageNum, pageCount).toString();
        });

        // Se estamos em modo de impressão/preview, cria numeração por página
        if (window.matchMedia('print').matches || isInPrintPreview()) {
            createSequentialPageNumbers(pageCount);
        }
    }

    function isInPrintPreview() {
        // Detecta se estamos em preview de impressão
        return window.location.href.includes('print-preview') ||
               document.body.classList.contains('print-preview') ||
               window.matchMedia('print').matches;
    }

    function createSequentialPageNumbers(totalPages) {
        // Remove numerações anteriores
        const oldNums = document.querySelectorAll('.sequential-page-num');
        oldNums.forEach(el => el.remove());

        // Cria numeração sequencial
        for (let i = 1; i <= totalPages; i++) {
            const numElement = document.createElement('span');
            numElement.className = 'sequential-page-num';
            numElement.textContent = i.toString();
            numElement.style.cssText = `
                position: absolute;
                bottom: 10px;
                right: 10px;
                font-size: 12.5px;
                color: var(--blue);
                font-weight: 700;
                z-index: 9999;
                page-break-inside: avoid;
            `;

            // Anexa ao final do body para cada página
            document.body.appendChild(numElement);
        }
    }

    // Função para recriar numeração em contexto de impressão
    function handlePrintMode() {
        // Detecta quando entra em modo de impressão
        if (window.matchMedia) {
            const mediaQueryList = window.matchMedia('print');
            mediaQueryList.addListener(function(mq) {
                if (mq.matches) {
                    // Entrando em modo impressão
                    setTimeout(function() {
                        createMultiplePageFooters();
                    }, 50);
                }
            });
        }

        // Detecta preview de impressão via beforeprint
        window.addEventListener('beforeprint', function() {
            setTimeout(function() {
                createMultiplePageFooters();
            }, 10);
        });
    }

    function createMultiplePageFooters() {
        // Abordagem simplificada: cria vários elementos de página numerados
        const pageElements = document.querySelectorAll('.cover-page, .flow-page');
        let pageCount = Math.max(pageElements.length, 2); // Mínimo 2 páginas

        // Se não encontrou elementos de página, estima pela altura
        if (pageElements.length === 0) {
            const totalHeight = document.documentElement.scrollHeight;
            const pageHeight = Math.max(window.innerHeight, 1056); // Altura da página
            pageCount = Math.ceil(totalHeight / pageHeight);
        }

        // Cria elementos de numeração para cada página
        const footer = document.querySelector('.footer');
        if (!footer) return;

        // Remove numerações antigas
        const oldNumbers = document.querySelectorAll('.page-number-js');
        oldNumbers.forEach(el => el.remove());

        // Cria numeração para cada página
        for (let i = 1; i <= pageCount; i++) {
            const pageNumDiv = document.createElement('div');
            pageNumDiv.className = 'page-number-js';
            pageNumDiv.textContent = i.toString();
            pageNumDiv.style.cssText = `
                position: fixed;
                bottom: 32px;
                right: 56px;
                font-size: 12.5px;
                color: var(--blue);
                font-weight: 700;
                z-index: 1000;
                page: page-${i};
            `;
            document.body.appendChild(pageNumDiv);
        }

        // Força atualização do layout
        setTimeout(() => {
            window.dispatchEvent(new Event('resize'));
        }, 10);
    }

    // Função para otimizar quebras de página (mantida do sistema original)
    function optimizePageBreaks() {
        const sections = document.querySelectorAll('.content-section');
        const pageHeight = 297; // mm - altura da página A4
        const footerHeight = 120; // mm
        const availableHeight = pageHeight - footerHeight;

        let currentHeight = 0;

        sections.forEach(function(section) {
            const sectionHeight = section.offsetHeight * 0.352778; // px to mm conversion

            // Se a seção não cabe na página atual, força quebra
            if (currentHeight + sectionHeight > availableHeight) {
                section.classList.add('js-page-break');
                currentHeight = sectionHeight;
            } else {
                currentHeight += sectionHeight;
            }
        });
    }

    // Inicialização
    setupPageNumbers();
    handlePrintMode();

    // Marca que JavaScript está ativo para override do CSS
    document.body.classList.add('js-pagination');

    // Executar otimização se solicitado
    if (window.location.search.includes('optimize=true')) {
        setTimeout(optimizePageBreaks, 100);
    }
});

