// Sistema de paginação simples e funcional
document.addEventListener('DOMContentLoaded', function() {
    // Substitui números de página CSS por JavaScript
    function initializePagination() {
        // Remove dependência dos contadores CSS
        document.body.classList.add('js-pagination');

        // Atualiza números imediatamente
        updatePageNumbers();

        // Detecta preview/impressão
        window.addEventListener('beforeprint', handlePrintMode);

        // Recalcula quando necessário
        window.addEventListener('resize', function() {
            setTimeout(updatePageNumbers, 100);
        });
    }

    function updatePageNumbers() {
        // Encontra o elemento de numeração
        const pageNumElement = document.querySelector('.pg-num');
        if (pageNumElement) {
            // Força exibição do número 1 na primeira página
            pageNumElement.textContent = '1';
            pageNumElement.style.fontSize = '12.5px';
            pageNumElement.style.color = 'var(--blue)';
            pageNumElement.style.fontWeight = '700';
        }
    }

    function handlePrintMode() {
        // Cria sistema de múltiplos footers para impressão
        createPrintFooters();
    }

    function createPrintFooters() {
        // Remove footers de impressão anteriores
        const oldPrintFooters = document.querySelectorAll('.print-footer');
        oldPrintFooters.forEach(f => f.remove());

        // Calcula páginas estimadas
        const contentHeight = document.documentElement.scrollHeight;
        const pageHeight = 1123; // Aproximadamente 297mm (A4) em pixels
        const estimatedPages = Math.max(Math.ceil(contentHeight / pageHeight), 3);

        // Cria footer numerado para cada página
        for (let page = 1; page <= estimatedPages; page++) {
            const footer = createFooterElement(page, pageHeight);
            document.body.appendChild(footer);
        }
    }

    function createFooterElement(pageNumber, pageHeight) {
        const footer = document.createElement('div');
        footer.className = 'print-footer';
        footer.innerHTML = `
            <div style="height: 2px; background: #e5e7eb80; margin-bottom: 24px;"></div>
            <div style="display: flex; justify-content: space-between; align-items: center; padding: 0 56px;">
                <div>
                    <img src="Logo completa.png" alt="Wa Project" style="width: 74px; height: 27px;">
                </div>
                <span style="font-size: 12.5px; color: var(--blue); font-weight: 700;">${pageNumber}</span>
            </div>
        `;

        // Posicionamento específico para cada página
        footer.style.cssText = `
            position: fixed;
            bottom: 0;
            left: 0;
            right: 0;
            padding: 24px 0 0;
            background: rgba(252, 252, 252, 0.95);
            backdrop-filter: blur(2px);
            z-index: 10;
            page-break-inside: avoid;
            -webkit-print-color-adjust: exact;
            print-color-adjust: exact;
            transform: translateY(${(pageNumber - 1) * pageHeight}px);
        `;

        return footer;
    }

    // Melhor distribuição de conteúdo entre páginas
    function optimizeContentFlow() {
        // Ajusta quebras de página para melhor distribuição
        const sections = document.querySelectorAll('.content-section');
        sections.forEach(function(section, index) {
            // Remove quebras forçadas existentes
            section.style.pageBreakBefore = '';
            section.classList.remove('js-page-break');

            // Aplica quebra estratégica na metade das seções
            if (index === Math.floor(sections.length / 2)) {
                section.style.pageBreakBefore = 'always';
                section.classList.add('js-page-break');
            }
        });
    }

    // Inicialização
    initializePagination();

    // Otimiza fluxo de conteúdo se solicitado
    if (window.location.search.includes('optimize=true')) {
        setTimeout(optimizeContentFlow, 200);
    }
});

